diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 255ce6973a16..479f1a4d0859 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3333,7 +3333,22 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
     break;
   }
   }
-
+  // If the selects have swapped arms and the intrinsic is commutative,
+  // the result is independent of the condition.
+  if (II->arg_size() >= 2) {
+    Value *A, *B, *C, *D, *E, *F;
+    if (match(II->getArgOperand(0),
+              m_Select(m_Value(A), m_Value(B), m_Value(C))) &&
+        match(II->getArgOperand(1),
+              m_Select(m_Value(D), m_Value(E), m_Value(F))) &&
+        A == D && B == F && C == E && II->isCommutative() &&
+        isSafeToSpeculativelyExecute(II)) {
+      // For FP intrinsics, preserve fast-math flags.
+      Instruction *FMFSource = isa<FPMathOperator>(II) ? II : nullptr;
+      Value *NewCall = Builder.CreateBinaryIntrinsic(IID, B, E, FMFSource);
+      return replaceInstUsesWith(*II, NewCall);
+    }
+  }
   // Try to fold intrinsic into select operands. This is legal if:
   //  * The intrinsic is speculatable.
   //  * The select condition is not a vector, or the intrinsic does not
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..cd06d4769337 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1143,6 +1143,16 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
       else if (True && !False)
         False = Builder.CreateBinOp(Opcode, C, F);
     }
+
+  // If the selects have swapped arms and the operation is commutative,
+  // the result is independent of the condition.
+  if (!True && !False && B == F && C == E && I.isCommutative() &&
+      isSafeToSpeculativelyExecute(&I)) {
+    Value *NewBO = Builder.CreateBinOp(Opcode, B, E);
+    if (auto *BO = dyn_cast<BinaryOperator>(NewBO))
+      BO->copyIRFlags(&I);
+    return NewBO;
+  }
   } else if (LHSIsSelect && LHS->hasOneUse()) {
     // (A ? B : C) op Y -> A ? (B op Y) : (C op Y)
     Cond = A;

